INSERT INTO `ai_qa_log` (`id`, `user_id`, `question`, `answer`, `source`, `response_time`, `create_time`, `citations`) VALUES (1,'anonymous','你能工作吗','感谢您的咨询。如需帮助，请联系宿舍管理员或查看系统帮助文档。','FALLBACK',20594,'2026-06-17 17:01:28',NULL),(2,'student','你能工作吗','当然可以工作！我是你的宿管小助手，随时准备帮你解答宿舍收费和管理相关的问题。请问你想了解哪方面的内容？比如住宿费标准、缴费流程、调换宿舍、退费申请等，都可以告诉我哦~ 😊','AI',3741,'2026-06-17 17:06:39',NULL),(3,'admin','你好','您好！我是宿管小助手 👋\n我可以帮您解答以下问题：\n- 📋 宿舍入住与调换流程\n- 💰 收费项目及标准查询\n- 🧾 缴费账单查询\n- 💳 在线缴费操作指导\n- 📊 报表导出说明\n- ⚠️ 逾期处理与退费申请\n\n请问有什么可以帮助您的？','GREETING',0,'2026-06-17 18:46:26',NULL),(4,'admin','住宿费多少钱？','宿舍收费项目及标准：\n1. 住宿费 -- 1200元/学期（标准四人间）\n2. 水费 -- 5元/吨（按实际用量）\n3. 电费 -- 0.6元/度（按实际用量）\n4. 空调费 -- 300元/学期\n5. 网络费 -- 50元/月\n6. 热水费 -- 按实际用量计费\n具体费用以系统中的收费项目页面为准，不同宿舍类型收费标准可能有所不同。','LOCAL_KB',0,'2026-06-17 18:46:41',NULL),(5,'admin','住宿费多少钱','宿舍收费项目及标准：\n1. 住宿费 -- 1200元/学期（标准四人间）\n2. 水费 -- 5元/吨（按实际用量）\n3. 电费 -- 0.6元/度（按实际用量）\n4. 空调费 -- 300元/学期\n5. 网络费 -- 50元/月\n6. 热水费 -- 按实际用量计费\n具体费用以系统中的收费项目页面为准，不同宿舍类型收费标准可能有所不同。','LOCAL_KB',0,'2026-06-17 20:05:08',NULL),(6,'admin','住宿费多少钱','您好！关于住宿费的具体金额，不同宿舍类型（如四人间、六人间、普通宿舍或公寓）的收费标准会有所不同，且可能随学年或政策调整。\n\n建议您**登录宿舍收费管理系统**，在“收费标准”模块中查看您所在宿舍楼及房型的**最新收费标准**，或直接联系宿舍管理员获取准确信息。如果您方便的话，也可以告诉我您的宿舍楼号和房型，我可以帮您查阅系统中存储的通用标准（但具体金额仍需以系统内最新数据为准）。😊','AI',5372,'2026-06-17 20:07:15',NULL),(7,'admin','住宿费收费标准是什么','您好！关于住宿费收费标准，不同宿舍类型的价格有所差异，以下为常见宿舍类型对应的**参考标准**（具体金额以系统内最新数据为准）：\n\n| 宿舍类型 | 参考收费标准（元/学年） |\n|---------|---------------------|\n| 四人间（普通宿舍） | 1200 - 1500 |\n| 六人间（普通宿舍） | 800 - 1000 |\n| 八人间（普通宿舍） | 600 - 800 |\n| 公寓型四人间（带独立卫浴） | 1500 - 2000 |\n| 公寓型双人间 | 2000 - 3000 |\n\n**温馨提示：**\n- 部分宿舍楼因楼层、朝向、设施新旧等因素可能价格略有浮动。\n- 水费、电费、空调费通常**不包含**在住宿费内，按实际用量另行计费（具体单价请见系统“收费标准”模块）。\n- 如果您的宿舍类型未在表中列出，或需要确认您所住宿舍的准确金额，请**登录宿舍收费管理系统**，在“收费标准”或“我的账单”中查看。\n\n建议您登录系统核对最新收费标准，如有疑问可咨询宿舍管理员。😊','AI',5741,'2026-06-17 20:09:33',NULL),(8,'admin','住宿费收费标准是什么','您好！我是宿管小助手，很高兴为您解答住宿费相关问题。\n\n关于住宿费收费标准，由于不同宿舍类型（如四人间、六人间、八人间、公寓楼等）收费标准可能不同，且最新价格以学校文件为准，目前我无法直接提供确切的金额。建议您通过以下方式获取准确信息：\n\n- ✅ **登录学生宿舍收费管理系统**，在“收费标准”模块查看您所在宿舍楼的具体价格。\n- ✅ 咨询本楼栋宿舍管理员，获取最新的收费公示表。\n\n如果您有具体宿舍类型（如“新公寓四人间”），我可以尝试帮您查找知识库中的参考信息，但最终请以系统显示为准。','AI',4039,'2026-06-17 20:13:45',NULL),(9,'admin','住宿费多少钱','您好！根据宿舍类型的不同，住宿费标准如下：\n\n| 宿舍类型 | 收费标准（元/学期） |\n|---------|------------------|\n| 标准四人间 | 1,200 |\n| 双人间 | 1,800 |\n| 单人间 | 2,500 |\n| 留学生公寓 | 3,000 |\n\n住宿费按学期缴纳，包含物业管理费、公共区域水电费和垃圾清运费，但不含房间内自用的水电费。\n\n---\n📚 **参考来源：**\n- [1] 《宿舍收费标准明细.md》（相关度: 0.5328）\n- [2] 《常见问题FAQ.md》（相关度: 0.504）\n- [3] 《常见问题FAQ.md》（相关度: 0.4634）','AI',4545,'2026-06-17 20:18:26',NULL),(10,'admin','如何才能申请换宿舍，流程是什么样的','[流式回答]','AI_STREAM',0,'2026-06-17 20:26:45',NULL),(11,'admin','如何才能申请换宿舍，流程是什么样的','[流式回答]','AI_STREAM',0,'2026-06-17 20:26:45',NULL),(12,'admin','如何申请调换宿舍','[流式回答]','AI_STREAM',0,'2026-06-17 20:33:58',NULL),(13,'admin','如何申请调换宿舍','[流式回答]','AI_STREAM',0,'2026-06-17 20:33:59',NULL),(14,'admin','住宿费多少钱？','[流式回答]','AI_STREAM',0,'2026-06-17 20:39:58',NULL),(15,'admin','如何换宿舍？','[流式回答]','AI_STREAM',0,'2026-06-17 20:40:15',NULL),(16,'admin','你好','您好！我是宿管小助手 👋\n我可以帮您解答以下问题：\n- 📋 宿舍入住与调换流程\n- 💰 收费项目及标准查询\n- 🧾 缴费账单查询\n- 💳 在线缴费操作指导\n- 📊 报表导出说明\n- ⚠️ 逾期处理与退费申请\n\n请问有什么可以帮助您的？','GREETING',0,'2026-06-27 11:00:17',NULL),(17,'admin','住宿费多少钱？','[流式回答]','AI_STREAM',0,'2026-06-27 13:44:50',NULL),(18,'admin','如何换宿舍？','[流式回答]','AI_STREAM',0,'2026-06-27 13:45:14',NULL),(19,'admin','住宿费多少钱？','[流式回答]','AI_STREAM',0,'2026-06-27 20:05:56',NULL),(20,'admin','住宿费多少钱？','根据《宿舍收费标准》[1]，住宿费按宿舍类型收取：\n\n- **标准四人间**：1200元/学期  \n- **双人间**：1800元/学期  \n- **单人间**：2500元/学期  \n\n具体费用需以你实际入住的宿舍类型为准，建议登录系统查看最新信息~','AI',4197,'2026-06-27 20:29:58','[{\"markerId\":1,\"chunkId\":\"8cea2f90-dc7\",\"docId\":10,\"docTitle\":\"�����շѱ�׼\",\"content\":\"# 宿舍收费标准\\n\\n## 住宿费\\n- 标准四人间：1200元/学期\\n- 双人间：1800元/学期\\n- 单人间：2500元/学期\\n\\n## 水费\\n- 冷水：5元/吨\\n- 热水：15元/吨\\n\\n## 电费\\n- 0.6元/度，按实际使用量计费\\n\\n## 空调费\\n- 300元/学期\\n\\n## 网络费\\n- 50元/月\",\"chunkIndex\":0,\"score\":0.5198,\"confidence\":\"HIGH\",\"referenced\":true}]'),(21,'admin','怎么缴费？','[流式回答]','AI_STREAM',0,'2026-06-27 20:49:24',NULL),(22,'diagnostic','ping','您好，我是“宿管小助手”，专门解答宿舍收费管理相关问题。您输入的“ping”是网络连通性测试命令，这不在我的服务范围内哦😊。\n\n如果您想了解宿舍网络设置或网络问题，建议您联系宿管老师或学校网络中心处理。如果您有其他宿舍收费、缴费、住宿等业务问题，欢迎随时问我！','AI',7005,'2026-06-29 16:18:37',NULL),(23,'admin','test','[流式回答]','AI_STREAM',0,'2026-06-29 16:20:46',NULL),(24,'diagnostic','ping','您好，我是“宿管小助手”，专注于解答宿舍收费管理相关问题。您输入的“ping”是网络连通性测试命令，不属于我的业务范围哦😊。\n\n如果您有关于宿舍住宿、收费标准、账单查询、在线缴费、报表导出、逾期处理或退费申请等需求，欢迎随时提出，我会尽力帮助您！若需要宿舍网络设置帮助，请联系宿管老师或学校网络中心。','AI',6228,'2026-06-29 16:25:12',NULL),(25,'admin','怎么办理入住？','[流式回答]','AI_STREAM',0,'2026-06-29 16:25:34',NULL),(26,'admin','住宿费多少钱？','[流式回答]','AI_STREAM',0,'2026-06-29 16:48:49',NULL),(27,'student','住宿费多少钱？','[流式回答]','AI_STREAM',0,'2026-06-29 21:45:27',NULL),(28,'student','住宿费多少钱？','[流式回答]','AI_STREAM',0,'2026-06-29 21:49:35',NULL);
