CREATE TABLE `dormitory` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `dormitory_no` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '宿舍编号',
  `building` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '楼栋',
  `floor` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '楼层',
  `room_type` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '房间类型',
  `capacity` int DEFAULT '4' COMMENT '容纳人数',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_dormitory_no` (`dormitory_no`),
  KEY `idx_building` (`building`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=209 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='宿舍信息表';
