  `fee_type` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '收费类型',
  `unit_price` decimal(10,2) NOT NULL COMMENT '收费单价',
  `billing_cycle` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '计费周期',
  `applicable_dorm_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'ALL' COMMENT '适用宿舍类型',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVE' COMMENT '状态',
  `description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '收费说明',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `idx_fee_type` (`fee_type`),
  KEY `idx_status` (`status`),
  KEY `idx_billing_cycle` (`billing_cycle`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='收费项目表';
