INSERT INTO `kb_chunk` (`id`, `document_id`, `chunk_index`, `content`, `token_count`, `create_time`, `chunk_id`) VALUES (104,13,0,'# 常见问题 FAQ\n\n## 住宿相关\n\n### Q1：新生如何申请宿舍？\n新生收到录取通知书后，在规定时间内登录迎新系统提交住宿申请，学校统一分配宿舍和床位。申请通过后在系统缴纳住宿费即可。\n\n### Q2：宿舍是几人间？可以自己选吗？\n默认分配四人间。学校也提供双人间和单人间，数量有限，需额外申请并缴纳对应费用。宿舍由系统统一分配，不接受指定房间号。\n\n### Q3：宿舍有哪些设施？\n标准宿舍配有床铺、书桌、衣柜、空调（部分楼栋）、网络接口、独立卫生间。公共区域设有热水器、洗衣机（扫码付费使用）。\n\n### Q4：可以自己带电器吗？\n可以使用笔记本电脑、手机充电器、台灯等低功率电器。**严禁使用大功率电器**（如电炉、热得快、电热毯、电磁炉等），功率上限为 800W。\n\n## 收费相关\n\n### Q5：住宿费多少钱一学期？\n- 四人间：1200 元/学期\n- 双人间：1800 元/学期\n- 单人间：2500 元/学期\n- 留学生公寓：3000 元/学期',355,'2026-06-27 20:47:48','ca9aa62c-9c2'),(105,13,1,'\n\n## 收费相关\n\n### Q5：住宿费多少钱一学期？\n- 四人间：1200 元/学期\n- 双人间：1800 元/学期\n- 单人间：2500 元/学期\n- 留学生公寓：3000 元/学期\n\n### Q6：水电费怎么算？\n- 水费：5 元/吨，按宿舍水表实际用量计费\n- 电费：0.6 元/度，每宿舍每月有 20 度免费额度，超出部分按实际用量收费\n- 热水：0.1 元/升，刷卡取水\n\n### Q7：空调费和网络费是必须交的吗？\n- 空调费：仅限安装空调的宿舍，300 元/学期\n- 网络费：自愿开通，50 元/月（标准套餐）\n\n### Q8：缴费截止日期是什么时候？\n- 住宿费和空调费：每学期开学后第 7 天\n- 水电费：每月 7 日前缴纳上月费用\n- 网络费：随住宿费一同缴纳\n\n### Q9：可以延期缴费吗？\n原则上需按时缴费。如因经济困难，可在截止日前联系学生资助管理中心申请延期（最多延 30 天，免滞纳金）。\n\n## 缴费相关',310,'2026-06-27 20:47:48','a76f7853-158'),(106,13,2,'如因经济困难，可在截止日前联系学生资助管理中心申请延期（最多延 30 天，免滞纳金）。\n\n## 缴费相关\n\n### Q10：怎么在线缴费？\n1. 登录学生宿舍收费管理系统\n2. 点击「收费管理」→「我的账单」\n3. 勾选待缴账单，点「去支付」\n4. 跳转支付宝完成支付\n5. 系统自动更新缴费状态\n\n### Q11：支持哪些支付方式？\n目前仅支持支付宝在线支付。如需其他方式（如银行转账），请联系财务处。\n\n### Q12：缴费后状态没更新怎么办？\n支付成功后系统会在 1—2 分钟内同步状态。如超过 5 分钟仍未更新，请联系管理员，提供支付宝交易流水号。\n\n### Q13：可以代别人缴费吗？\n可以。登录后可以帮其他同学缴费，但需在支付页面备注被代缴人学号和姓名。\n\n## 逾期相关\n\n### Q14：逾期了会怎么样？\n- 产生滞纳金（1%—10%，按逾期天数递增）\n- 逾期记录记入学生诚信档案\n- 逾期超过 30 天取消住宿资格\n\n### Q15：逾期了还能补救吗？\n可以。尽快登录系统补缴欠费和滞纳金。如因特殊情况导致逾期，可联系管理员说明情况，可能免除部分滞纳金。\n\n## 退费相关',404,'2026-06-27 20:47:48','e0930fd4-3fa'),(107,13,3,'尽快登录系统补缴欠费和滞纳金。如因特殊情况导致逾期，可联系管理员说明情况，可能免除部分滞纳金。\n\n## 退费相关\n\n### Q16：中途退宿能退住宿费吗？\n可以。按实际住宿天数结算：\n- 退费 = 已缴住宿费 − 已住天数 × 日住宿费\n- 四人间日住宿费 ≈ 8 元/天\n\n### Q17：退费多久到账？\n审批通过后 3—5 个工作日，原路退回支付宝账户。\n\n### Q18：毕业了剩余的住宿费退不退？\n正常毕业情况下，按完整学期计算，住宿费不退。如因特殊情况提前毕业，按实际天数结算。\n\n## 调换宿舍\n\n### Q19：怎么申请换宿舍？\n向辅导员提交《宿舍调换申请表》，辅导员核实后交宿舍管理科审核，审批通过后办理搬离和迁入。\n\n### Q20：换宿舍后费用会变吗？\n会。如果从四人间换到双人间，需补交差价（600 元/学期）。反之，多余部分退还。\n\n## 网络和热水\n\n### Q21：网络怎么开通？\n登录系统，在「收费管理」→「网络费」中选择套餐并缴费。缴费成功后 1 小时内自动开通。\n\n### Q22：热水什么时间段有？\n每日 06:00—09:00、17:00—23:00。寒暑假期间热水供应时间可能调整。',409,'2026-06-27 20:47:48','8143e3f6-87c'),(108,13,4,'缴费成功后 1 小时内自动开通。\n\n### Q22：热水什么时间段有？\n每日 06:00—09:00、17:00—23:00。寒暑假期间热水供应时间可能调整。\n\n### Q23：WiFi 信号不好怎么办？\n- 确认网络费已缴纳且未过期\n- 尝试连接 5GHz 频段（信号更好）\n- 如持续不好，联系网络中心报修\n\n## 安全和其他\n\n### Q24：宿舍楼门禁几点关门？\n周日至周四 23:00，周五周六 23:30。考试周关门时间延至 00:30。\n\n### Q25：丢了钥匙怎么办？\n到各楼栋管理处登记挂失，补办钥匙工本费 10 元。如遗失门禁卡，补办费 20 元。\n\n### Q26：宿舍东西坏了找谁修？\n登录系统进入「报修」页面提交报修申请，或直接联系楼栋管理员。一般维修 24 小时内响应，紧急维修（漏水、断电等）2 小时内响应。\n\n---\n\n> 以上 FAQ 基于最新制度整理，如有变化以系统公告为准。\n> 其他问题请联系宿舍管理科：A栋一楼，010-xxxx-8002',320,'2026-06-27 20:47:48','32dd2b60-f7d'),(109,18,0,'# 在线缴费操作指南\n\n## 一、登录系统\n\n### 1.1 访问地址\n\n- **校园网内**：http://dormitory.campus.edu.cn\n- **校外访问**：通过 VPN 连接后访问\n\n### 1.2 登录账号\n\n- **用户名**：学号\n- **初始密码**：身份证后 6 位（首次登录后请立即修改）\n\n## 二、查看账单\n\n### 2.1 进入缴费页面\n\n登录系统后，在左侧导航栏找到「收费管理」→「我的账单」。\n\n### 2.2 账单状态说明\n\n| 状态 | 含义 | 颜色标识 |\n|------|------|---------|\n| 未缴 | 账单已生成，待缴费 | 橙色 |\n| 已缴 | 已完成缴费 | 绿色 |\n| 逾期 | 超过缴费截止日期未缴 | 红色 |\n\n### 2.3 账单详情\n\n点击任意账单可查看：\n- 收费项目名称\n- 应缴金额\n- 缴费截止日期\n- 缴费状态\n- 缴费记录（如有）\n\n## 三、在线缴费步骤\n\n### 3.1 选择待缴账单\n\n1. 在「我的账单」页面，勾选要缴纳的账单（可多选）\n2. 系统自动计算合计金额\n3. 确认无误后点击「去支付」按钮',322,'2026-06-27 20:48:07','44c41a39-945'),(110,18,1,'费项目名称\n- 应缴金额\n- 缴费截止日期\n- 缴费状态\n- 缴费记录（如有）\n\n## 三、在线缴费步骤\n\n### 3.1 选择待缴账单\n\n1. 在「我的账单」页面，勾选要缴纳的账单（可多选）\n2. 系统自动计算合计金额\n3. 确认无误后点击「去支付」按钮\n\n### 3.2 支付宝支付\n\n1. 系统自动跳转至支付宝收银台\n2. 使用支付宝 App 扫描屏幕上的二维码\n3. 在手机上确认支付金额和收款方\n4. 输入支付密码完成支付\n5. 等待 3—5 秒，系统自动跳回并显示支付结果\n\n> **注意**：当前为支付宝沙箱测试环境，仅支持沙箱测试账号支付。正式上线后将切换为正式支付宝支付接口。\n\n### 3.3 支付确认\n\n- 支付成功后，系统自动更新账单状态为「已缴」\n- 可在「支付记录」中查看电子缴费凭证\n- 如遇网络延迟，支付状态可能在 1—2 分钟内同步\n\n### 3.4 支付失败处理\n\n如果支付失败，请检查：\n\n1. 支付宝余额是否充足\n2. 网络连接是否正常\n3. 是否在支付宝沙箱环境中操作\n\n支付失败不会产生重复扣款，可关闭支付宝页面后重新发起支付。\n\n## 四、缴费凭证\n\n### 4.1 查看凭证',395,'2026-06-27 20:48:07','b694b2a9-226'),(111,18,2,'\n\n## 四、缴费凭证\n\n### 4.1 查看凭证\n\n进入「收费管理」→「支付记录」：\n- 可查看所有历史支付记录\n- 每个支付记录旁有「查看凭证」按钮\n- 凭证包含：缴费人、学号、缴费项目、金额、支付时间、交易流水号\n\n### 4.2 打印凭证\n\n- 点击「打印凭证」可打印标准格式的缴费收据\n- 如需盖章，请前往财务处办理\n\n## 五、常见问题\n\n### Q1：缴费后状态没更新？\n\n答：支付宝支付成功后，系统会在 1—2 分钟内同步状态。如超过 5 分钟仍未更新，请联系管理员，提供支付宝交易流水号进行人工核实。\n\n### Q2：可以部分缴费吗？\n\n答：目前不支持部分缴费。如需分期缴纳，请联系财务处申请。\n\n### Q3：缴费收据丢了怎么办？\n\n答：登录系统进入「支付记录」可随时查看和重新打印电子凭证，无需担心丢失。\n\n### Q4：逾期了还能缴费吗？\n\n答：可以。逾期账单仍然可以正常缴费，但会产生逾期记录。建议尽快缴清，避免影响住宿资格。\n\n## 六、联系方式',362,'2026-06-27 20:48:07','c7e47593-8f9'),(112,18,3,'\n\n### Q4：逾期了还能缴费吗？\n\n答：可以。逾期账单仍然可以正常缴费，但会产生逾期记录。建议尽快缴清，避免影响住宿资格。\n\n## 六、联系方式\n\n- **财务处**：行政楼 2 楼，电话 010-xxxx-8001\n- **宿舍管理科**：A栋一楼管理处，电话 010-xxxx-8002\n- **技术支持**：如遇系统问题，发邮件至 dormitory-support@campus.edu.cn',126,'2026-06-27 20:48:07','bca3f556-8fb'),(113,14,0,'# 宿舍调换与退费流程\n\n## 一、宿舍调换\n\n### 1.1 申请条件\n\n满足以下任意一条可申请调换宿舍：\n\n| 条件 | 所需材料 |\n|------|---------|\n| 室友矛盾经调解无效 | 辅导员调解记录 + 调换申请表 |\n| 身体原因需特殊安排 | 医院证明 + 调换申请表 |\n| 专业校区调整 | 学院证明 + 调换申请表 |\n| 宿舍设施严重损坏 | 维修记录 + 调换申请表 |\n\n### 1.2 申请流程\n\n```\n提交申请表 → 辅导员签字 → 宿舍管理科审核 → 查询空床位 → 审批 → 搬离/迁入\n    ↓              ↓              ↓             ↓          ↓         ↓\n  学生本人      3个工作日内     核实情况      数据库查询   3个工作日   5个工作日内完成\n```\n\n### 1.3 注意事项',244,'2026-06-27 20:48:37','fff56b54-1b1'),(114,14,1,' ↓              ↓             ↓          ↓         ↓\n  学生本人      3个工作日内     核实情况      数据库查询   3个工作日   5个工作日内完成\n```\n\n### 1.3 注意事项\n\n- 调换申请每月 1—10 日集中受理，11—20 日为审核期，21 日起办理调换\n- 每学期最多申请调换 1 次\n- 调换后的宿舍费用按实际入住宿舍类型计算，多退少补\n- 未经批准私自调换宿舍者，按违规处理，扣 10 分\n\n## 二、退宿退费\n\n### 2.1 退宿类型\n\n| 类型 | 适用情况 | 费用结算方式 |\n|------|---------|-------------|\n| 毕业退宿 | 正常毕业离校 | 住宿费不退（已满整学期） |\n| 休学退宿 | 因病或其他原因休学 | 按实际天数结算，多退少补 |\n| 退学退宿 | 主动或被动退学 | 按实际天数结算，多退少补 |\n| 出国退宿 | 学期中出国交流 | 按实际天数结算，多退少补 |\n| 校外住宿 | 申请校外住宿获批 | 退回剩余学期的住宿费 |\n\n### 2.2 退费计算规则',323,'2026-06-27 20:48:37','a1adf7b1-d87'),(115,14,2,'天数结算，多退少补 |\n| 退学退宿 | 主动或被动退学 | 按实际天数结算，多退少补 |\n| 出国退宿 | 学期中出国交流 | 按实际天数结算，多退少补 |\n| 校外住宿 | 申请校外住宿获批 | 退回剩余学期的住宿费 |\n\n### 2.2 退费计算规则\n\n**住宿费退费**：\n\n```\n退费金额 = 已缴住宿费 − 已住宿天数 × 日住宿费\n\n日住宿费 = 学期住宿费 ÷ 学期总天数（约 150 天）\n```\n\n举例：\n- 标准四人间住宿费 1200 元/学期\n- 日住宿费 = 1200 ÷ 150 = 8 元/天\n- 如已住宿 30 天后退宿，退费 = 1200 − 30×8 = 960 元\n\n**空调费退费**：\n- 按剩余学期比例退费\n- 如使用不满半学期，退 50%；超过半学期，不退\n\n**网络费退费**：\n- 网络费按月结算\n- 已开通未满 1 个月，按 1 个月收费；超过 1 个月但不满 2 个月，按 2 个月收费\n\n### 2.3 退费流程',291,'2026-06-27 20:48:37','b23a57e3-8aa'),(116,14,3,'调费退费**：\n- 按剩余学期比例退费\n- 如使用不满半学期，退 50%；超过半学期，不退\n\n**网络费退费**：\n- 网络费按月结算\n- 已开通未满 1 个月，按 1 个月收费；超过 1 个月但不满 2 个月，按 2 个月收费\n\n### 2.3 退费流程\n\n1. **提交申请**：学生向宿舍管理科提交《退宿退费申请表》及相关证明材料\n2. **宿舍验收**：管理员到宿舍检查设施完好情况，填写《宿舍验收单》\n   - 设施损坏需照价赔偿，从退费中扣除\n   - 卫生不合格需清理干净后再次验收\n3. **费用核算**：财务处根据实际住宿天数核算退费金额\n4. **审批**：宿舍管理科科长审批\n5. **退款**：财务处在 3—5 个工作日内将款项原路退回至学生支付宝账户\n6. **确认**：学生收到退款后在系统中确认\n\n### 2.4 不予退费的情况\n\n- 因违规被取消住宿资格的，不予退费\n- 学期已超过 3/4 时间的，住宿费不予退还\n- 未完成宿舍验收流程的，暂不退费\n\n## 三、费用减免\n\n### 3.1 减免类型',350,'2026-06-27 20:48:37','12613701-fc3'),(117,14,4,'\n6. **确认**：学生收到退款后在系统中确认\n\n### 2.4 不予退费的情况\n\n- 因违规被取消住宿资格的，不予退费\n- 学期已超过 3/4 时间的，住宿费不予退还\n- 未完成宿舍验收流程的，暂不退费\n\n## 三、费用减免\n\n### 3.1 减免类型\n\n| 减免类型 | 减免比例 | 申请条件 |\n|---------|---------|---------|\n| 经济困难减免 | 最高 50% | 家庭经济困难认定 + 成绩合格 |\n| 学业优秀减免 | 20% | GPA 排名专业前 5% |\n| 勤工助学补贴 | 200 元/月 | 在宿舍管理科岗位服务 |\n| 残疾学生减免 | 30% | 持有残疾证明 |\n\n### 3.2 减免申请流程\n\n1. 每学期开学前 30 天内提交减免申请\n2. 提供相关证明材料（贫困证明、成绩单、残疾证等）\n3. 学生资助管理中心审核\n4. 审核通过后在缴费时自动抵扣\n\n> 减免申请每年需重新提交，不可自动延续。\n\n---\n\n## 四、联系方式',295,'2026-06-27 20:48:37','e4dae087-de6'),(118,14,5,'\n\n---\n\n## 四、联系方式\n\n- **宿舍管理科**：A栋一楼，电话 010-xxxx-8002\n- **财务处**：行政楼 2 楼，电话 010-xxxx-8001\n- **学生资助管理中心**：行政楼 1 楼，电话 010-xxxx-8003',65,'2026-06-27 20:48:37','ba171aa9-211'),(119,15,0,'# 宿舍收费标准明细\n\n## 一、收费项目总览\n\n| 序号 | 收费项目 | 收费标准 | 计费周期 | 适用对象 |\n|------|---------|---------|---------|---------|\n| 1 | 住宿费 | 1200 元/学期 | 按学期 | 全体住宿学生 |\n| 2 | 水费 | 5 元/吨 | 按月结算 | 全体住宿学生 |\n| 3 | 电费 | 0.6 元/度 | 按月结算 | 全体住宿学生 |\n| 4 | 空调费 | 300 元/学期 | 按学期 | 安装空调的宿舍 |\n| 5 | 网络费 | 50 元/月 | 按月 | 自愿开通 |\n| 6 | 热水费 | 0.1 元/升 | 按实际用量 | 使用热水系统的宿舍 |\n\n## 二、各项目详细说明\n\n### 2.1 住宿费\n\n- **标准四人间**：1200 元/学期\n- **双人间**：1800 元/学期\n- **单人间**：2500 元/学期\n- **留学生公寓**：3000 元/学期\n\n> 住宿费包含物业管理费、公共区域水电费、垃圾清运费。不含房间内自用水电费。\n\n### 2.2 水费',278,'2026-06-27 20:48:37','9aae075d-cff'),(120,15,1,'不含房间内自用水电费。\n\n### 2.2 水费\n\n- 冷水按水表实际用量计费，5 元/吨\n- 每学期初抄表记录基数，每学期末统一结算\n- 节约用水奖励：用水量低于平均水平 20% 的宿舍，下学期水费打 9 折\n\n### 2.3 电费\n\n- 按电表实际用量计费，0.6 元/度\n- 每个宿舍每月有 20 度免费基础用电额度（用于照明、风扇等基本需求）\n- 超出部分按 0.6 元/度计费\n- 每月 1 日抄表，生成上月电费账单\n\n### 2.4 空调费\n\n- 仅适用于安装空调的宿舍（A栋、B栋全部，C栋部分）\n- 300 元/学期，含空调日常维护费用\n- 空调使用期间（6月—9月、12月—2月）产生的额外电费包含在内\n- 非空调使用期间的电费按正常电费标准计算\n\n### 2.5 网络费\n\n- 50 元/月，包含校园网宽带接入和 WiFi 覆盖\n- 带宽：50Mbps（标准）/ 100Mbps（高速套餐 80 元/月）\n- 自愿开通，按学期预缴（5个月=250元，优惠50元）\n- 寒暑假期间可申请暂停，暂停期间不收费\n\n### 2.6 热水费',340,'2026-06-27 20:48:37','6626b1a9-432'),(121,15,2,'- 50 元/月，包含校园网宽带接入和 WiFi 覆盖\n- 带宽：50Mbps（标准）/ 100Mbps（高速套餐 80 元/月）\n- 自愿开通，按学期预缴（5个月=250元，优惠50元）\n- 寒暑假期间可申请暂停，暂停期间不收费\n\n### 2.6 热水费\n\n- 0.1 元/升，按水表实际用量计费\n- 热水供应时间：06:00—09:00、17:00—23:00\n- 使用校园卡刷卡取水\n\n## 三、缴费时间\n\n| 费用类型 | 缴费时间 | 截止日期 |\n|---------|---------|---------|\n| 住宿费 | 每学期开学前 2 周 | 开学后第 7 天 |\n| 空调费 | 随住宿费一同缴纳 | 同住宿费 |\n| 水费 | 每学期末结算 | 学期结束后 10 天内 |\n| 电费 | 每月 1—7 日 | 当月 7 日 |\n| 网络费 | 每学期开学前 | 开学后第 7 天 |\n| 热水费 | 每月 1—7 日 | 当月 7 日 |\n\n## 四、费用减免政策',265,'2026-06-27 20:48:37','3afd4f46-3a0'),(122,15,3,' |\n| 水费 | 每学期末结算 | 学期结束后 10 天内 |\n| 电费 | 每月 1—7 日 | 当月 7 日 |\n| 网络费 | 每学期开学前 | 开学后第 7 天 |\n| 热水费 | 每月 1—7 日 | 当月 7 日 |\n\n## 四、费用减免政策\n\n1. **家庭经济困难学生**：可申请住宿费减免，最高减免 50%\n2. **成绩优异学生**：上一学年 GPA 排名专业前 5% 者，下学期住宿费减免 20%\n3. **勤工助学岗位**：在宿舍管理科勤工助学的学生，可获得每月 200 元补贴\n4. **特殊困难**：因突发变故导致经济困难的，可单独提交减免申请\n\n减免申请需在每学期开学前 30 天内提交至学生资助管理中心，逾期不予受理。\n\n## 五、退费政策\n\n详见《宿舍调换与退费流程》文档。\n\n---\n\n> 以上收费标准经学校批准，自 2024 年 9 月起执行。',273,'2026-06-27 20:48:37','d03074f8-efb'),(123,16,0,'# 学生宿舍管理制度\n\n## 第一章 总则\n\n**第一条** 为规范学生宿舍管理，保障学生住宿安全，维护正常生活秩序，特制定本制度。\n\n**第二条** 本制度适用于本校所有在校住宿学生，包括本科生、研究生及留学生。\n\n**第三条** 学生宿舍管理坚持\"安全第一、服务为本、规范管理\"的原则。\n\n## 第二章 入住管理\n\n### 2.1 入住条件\n\n1. 本校正式注册的全日制在校学生\n2. 身体健康，无传染性疾病\n3. 已缴纳住宿费及相关费用\n4. 签订《学生住宿协议书》\n\n### 2.2 入住流程\n\n1. **提交申请**：新生入学时在迎新系统提交住宿申请，老生在每学期末提交下学期住宿申请\n2. **资格审核**：学生处对申请材料进行审核，3个工作日内反馈审核结果\n3. **分配宿舍**：宿舍管理科根据专业、年级、性别等因素统一分配宿舍和床位\n4. **缴纳费用**：通过学生宿舍收费管理系统在线缴纳住宿费（1200元/学期）及其他相关费用\n5. **领取钥匙**：凭缴费凭证到各楼栋管理处领取宿舍钥匙和门禁卡\n6. **入住登记**：填写《入住登记表》，确认宿舍设施完好情况\n\n### 2.3 床位分配规则',403,'2026-06-27 20:48:38','8c4eea85-7b7'),(124,16,1,'*缴纳费用**：通过学生宿舍收费管理系统在线缴纳住宿费（1200元/学期）及其他相关费用\n5. **领取钥匙**：凭缴费凭证到各楼栋管理处领取宿舍钥匙和门禁卡\n6. **入住登记**：填写《入住登记表》，确认宿舍设施完好情况\n\n### 2.3 床位分配规则\n\n- 原则上按同专业、同年级集中安排\n- 预留少量床位供特殊需求调整\n- 新生优先安排低楼层，高年级安排在较高楼层\n- 留学生单独安排留学生公寓\n\n## 第三章 宿舍调换\n\n### 3.1 调换条件\n\n学生有下列情况之一可申请调换宿舍：\n\n1. 与室友存在严重矛盾，经辅导员调解无效的\n2. 因身体原因（如过敏、残疾等）需调整住宿环境的\n3. 因专业调整导致上课地点与宿舍距离过远的\n4. 因宿舍设施严重损坏需整体搬迁的\n\n### 3.2 调换流程\n\n1. 学生向辅导员提交《宿舍调换申请表》\n2. 辅导员核实情况并签署意见\n3. 提交至宿舍管理科审核\n4. 宿舍管理科查询空余床位，3个工作日内回复\n5. 审批通过后，学生在5个工作日内完成搬离和迁入\n6. 办理钥匙/门禁卡交换手续\n\n## 第四章 退宿管理\n\n### 4.1 正常退宿',396,'2026-06-27 20:48:38','f2c17728-373'),(125,16,2,'换申请表》\n2. 辅导员核实情况并签署意见\n3. 提交至宿舍管理科审核\n4. 宿舍管理科查询空余床位，3个工作日内回复\n5. 审批通过后，学生在5个工作日内完成搬离和迁入\n6. 办理钥匙/门禁卡交换手续\n\n## 第四章 退宿管理\n\n### 4.1 正常退宿\n\n- 毕业离校时统一办理退宿\n- 离校前需完成宿舍验收（设施完好、卫生合格）\n- 退还钥匙和门禁卡\n- 结清所有费用\n\n### 4.2 中途退宿\n\n- 因病休学、退学、出国交流等情况可申请中途退宿\n- 需提前15天提交书面申请\n- 住宿费按实际住宿天数结算，多退少补\n\n## 第五章 日常管理\n\n### 5.1 作息时间\n\n| 时段 | 时间 |\n|------|------|\n| 开门时间 | 06:00 |\n| 关门时间 | 23:00（周日至周四）/ 23:30（周五、周六） |\n| 熄灯时间 | 23:30（考试周延长至 00:30） |\n\n### 5.2 访客管理\n\n- 访客需在值班室登记，出示有效证件\n- 访客时间：08:00 — 22:00\n- 异性访客不得进入宿舍楼层，仅限一楼接待区\n- 不得留宿外来人员，违者按校规处理',349,'2026-06-27 20:48:38','0a2658ca-9df'),(126,16,3,'\n| 熄灯时间 | 23:30（考试周延长至 00:30） |\n\n### 5.2 访客管理\n\n- 访客需在值班室登记，出示有效证件\n- 访客时间：08:00 — 22:00\n- 异性访客不得进入宿舍楼层，仅限一楼接待区\n- 不得留宿外来人员，违者按校规处理\n\n### 5.3 卫生管理\n\n- 每个宿舍制定值日表，每日打扫\n- 每周三下午为全校卫生检查日\n- 每月进行文明宿舍评比\n\n## 第六章 安全管理\n\n1. 严禁使用大功率电器（电炉、热得快、电热毯等），功率上限为 800W\n2. 严禁在宿舍内吸烟、使用明火\n3. 严禁私拉乱接电线、改装电路\n4. 离开宿舍时关闭电源、水源、门窗\n5. 贵重物品自行妥善保管，丢失自负\n6. 发现安全隐患及时报告宿舍管理员\n\n## 第七章 违规处理',257,'2026-06-27 20:48:38','7a3b1f86-1d2'),(127,16,4,'（电炉、热得快、电热毯等），功率上限为 800W\n2. 严禁在宿舍内吸烟、使用明火\n3. 严禁私拉乱接电线、改装电路\n4. 离开宿舍时关闭电源、水源、门窗\n5. 贵重物品自行妥善保管，丢失自负\n6. 发现安全隐患及时报告宿舍管理员\n\n## 第七章 违规处理\n\n| 违规行为 | 处理措施 |\n|---------|---------|\n| 使用违规电器 | 没收电器 + 通报批评 + 扣 5 分 |\n| 夜不归宿（累计 3 次） | 通报家长 + 取消住宿资格 |\n| 留宿外人 | 严重警告 + 扣 10 分 |\n| 破坏公共设施 | 照价赔偿 + 通报批评 |\n| 宿舍卫生不合格（累计 3 次） | 通报批评 + 取消评优资格 |\n\n扣分累计达到 15 分者，取消住宿资格，且不再安排校内住宿。\n\n---\n\n> 本制度自 2024 年 9 月 1 日起执行，解释权归学生宿舍管理科所有。',277,'2026-06-27 20:48:38','c4b3d71e-57f'),(128,17,0,'# 逾期处理与催缴机制\n\n## 一、逾期定义\n\n学生宿舍各项费用超过缴费截止日期仍未缴纳的，视为逾期。\n\n## 二、逾期影响\n\n### 2.1 信用记录\n\n- 逾期记录将记入学生诚信档案\n- 影响评奖评优、助学金申请\n- 影响毕业离校手续办理\n\n### 2.2 滞纳金\n\n| 逾期天数 | 滞纳金比例 | 计算方式 |\n|---------|-----------|---------|\n| 1—7 天 | 1% | 应缴金额 × 1% |\n| 8—15 天 | 3% | 应缴金额 × 3% |\n| 16—30 天 | 5% | 应缴金额 × 5% |\n| 30 天以上 | 10% | 应缴金额 × 10%（封顶） |\n\n> 滞纳金在应缴金额基础上额外收取，不减免。\n\n### 2.3 住宿资格\n\n- 逾期超过 30 天未缴费者，取消住宿资格\n- 取消住宿资格后需在 7 天内搬离宿舍\n- 搬离后仍需缴清所欠费用及滞纳金\n\n## 三、催缴机制\n\n### 3.1 自动提醒\n\n系统根据逾期时间自动发送提醒通知：',288,'2026-06-27 20:48:38','b92d59eb-e72'),(129,17,1,'\n\n### 2.3 住宿资格\n\n- 逾期超过 30 天未缴费者，取消住宿资格\n- 取消住宿资格后需在 7 天内搬离宿舍\n- 搬离后仍需缴清所欠费用及滞纳金\n\n## 三、催缴机制\n\n### 3.1 自动提醒\n\n系统根据逾期时间自动发送提醒通知：\n\n| 时间节点 | 通知方式 | 通知内容 |\n|---------|---------|---------|\n| 缴费截止前 3 天 | 短信 + 邮件 | 缴费提醒：您的xxx费用将于x月x日到期 |\n| 逾期第 1 天 | 短信 | 逾期通知：您有费用已逾期，请尽快缴费 |\n| 逾期第 7 天 | 邮件 | 逾期 7 天提醒，含滞纳金说明 |\n| 逾期第 15 天 | 短信 + 邮件 | 严重逾期警告 |\n| 逾期第 30 天 | 短信 + 邮件 + 辅导员通知 | 拟取消住宿资格通知 |\n\n### 3.2 通知内容示例\n\n**缴费提醒短信**：\n> 【宿舍管理系统】张三同学，您的住宿费 1200.00 元将于 2024年10月1日 到期，请及时登录系统缴费。如有疑问请联系宿舍管理科。',309,'2026-06-27 20:48:38','b814325d-74e'),(130,17,2,'如有疑问请联系宿舍管理科。\n\n**逾期通知邮件**：\n> 主题：【逾期通知】请尽快缴纳宿舍费用\n>\n> 亲爱的张三同学：\n>\n> 您的以下费用已逾期：\n> - 住宿费：1200.00 元（截止日期：2024年10月1日）\n> - 电费：45.60 元（截止日期：2024年10月1日）\n>\n> 逾期将产生滞纳金，并可能影响您的住宿资格和信用记录。请尽快登录学生宿舍收费管理系统完成缴费。\n>\n> 如有经济困难，请及时联系学生资助管理中心申请费用减免。\n>\n> 宿舍管理科\n> 联系电话：010-xxxx-8002\n\n## 四、逾期补缴\n\n- 逾期账单仍然可以在线缴费，系统自动计算滞纳金\n- 补缴后账单状态更新为「已缴」，但逾期记录保留\n- 如因系统原因导致逾期，可联系管理员核实后免除滞纳金\n\n## 五、特殊情况处理\n\n### 5.1 经济困难\n\n如因经济困难无法按时缴费：\n1. 在缴费截止日前联系学生资助管理中心\n2. 提交困难证明和延期缴费申请\n3. 获批后可延期 30 天缴费，免收滞纳金\n\n### 5.2 系统问题',353,'2026-06-27 20:48:38','b1b1e2f2-d4e'),(131,17,3,'管理员核实后免除滞纳金\n\n## 五、特殊情况处理\n\n### 5.1 经济困难\n\n如因经济困难无法按时缴费：\n1. 在缴费截止日前联系学生资助管理中心\n2. 提交困难证明和延期缴费申请\n3. 获批后可延期 30 天缴费，免收滞纳金\n\n### 5.2 系统问题\n\n如因系统故障导致无法缴费：\n1. 截图保存错误信息\n2. 立即联系技术支持（dormitory-support@campus.edu.cn）\n3. 经核实后可免除因系统故障产生的滞纳金\n\n### 5.3 争议处理\n\n如对账单有异议：\n1. 在缴费截止日前提交《费用异议申请表》\n2. 宿舍管理科在 5 个工作日内核实并回复\n3. 异议期间暂停计算滞纳金\n\n---\n\n## 附：日费率参考\n\n| 费用类型 | 日费率 | 月费率 |\n|---------|-------|-------|\n| 住宿费（四人间） | 8 元/天 | — |\n| 住宿费（双人间） | 12 元/天 | — |\n| 住宿费（单人间） | 16.67 元/天 | — |\n\n> 以上费率为估算值，精确计算以系统账单为准。',316,'2026-06-27 20:48:38','b57d0047-bd3');
