CREATE TABLE `kb_document` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '涓婚敭ID',
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鏂囨。鏍囬?',
  `description` varchar(1000) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鏂囨。鎻忚堪',
  `file_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鍘熷?鏂囦欢鍚',
  `file_type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鏂囦欢绫诲瀷: PDF/WORD/EXCEL/PPT/TXT/MD',
  `file_size` bigint NOT NULL COMMENT '鏂囦欢澶у皬(瀛楄妭)',
  `file_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'MinIO 瀵硅薄鍚',
  `chunk_count` int DEFAULT '0' COMMENT '鍒嗗潡鏁伴噺',
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PENDING' COMMENT 'PENDING/PROCESSING/COMPLETED/FAILED',
  `error_msg` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '澶辫触鍘熷洜',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`),
  KEY `idx_kb_doc_status` (`status`),
  KEY `idx_kb_doc_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='鐭ヨ瘑搴撴枃妗ｈ〃';
