--
-- Table structure for table `student_dormitory`
--

/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_dormitory` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `student_name` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '学生姓名',
  `student_no` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '学号',
  `dormitory_no` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '宿舍号',
  `phone` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '联系电话',
  `check_in_date` date NOT NULL COMMENT '入住时间',
  `payment_status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'UNPAID' COMMENT '缴费状态',
  `photo` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '学生照片URL',
  `deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '逻辑删除',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `user_id` bigint DEFAULT NULL COMMENT '关联系统用户ID (sys_user.id)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_student_no` (`student_no`),
  KEY `idx_dormitory_no` (`dormitory_no`),
  KEY `idx_payment_status` (`payment_status`),
  KEY `idx_student_name` (`student_name`),
  KEY `idx_user_id` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1007 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='学生宿舍信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

